+        let mut plus = a_data.to_vec();
+        plus[row * 2 + col] += eps;
+        if row != col {
+            plus[col * 2 + row] += eps;
+        }
+
+        let mut minus = a_data.to_vec();
+        minus[row * 2 + col] -= eps;
+        if row != col {
+            minus[col * 2 + row] -= eps;
+        }
+
+        let l_plus = loss_multi(
+            Primitive::Cholesky,
+            &make_f64_matrix(2, 2, &plus),
+            std::slice::from_ref(&g_l),
