+            for k in 0..3 {
+                spd[i * 3 + j] += b_data[k * 3 + i] * b_data[k * 3 + j];
+            }
+            if i == j {
+                spd[i * 3 + j] += 1e-8; // regularization
+            }
+        }
+    }
+
+    let a = make_f64_matrix(3, 3, &spd);
+    let outputs = eval_primitive_multi(
+        Primitive::Cholesky,
